};

const closeEditModal = () => {
  editVisible.value = false;
  editForm.value = {
    id: 0,
    title: "",
    description: "",
    startTime: "",
    endTime: "",
  };
};

const submitUpdateContest = async () => {
  if (!editForm.value.id) {
