  } catch (error) {
    message.error(getErrorMessage(error, "更新失败"));
  }
};

const doDelete = async (id: number) => {
  try {
    await deleteContest(id);
    message.success("删除成功");
    await loadContestList();
  } catch (error) {
    message.error(getErrorMessage(error, "删除失败"));
  }
};

